// n8n Code node — collect resultUrls from "Merge2" node (no uniqueness constraints)
const SOURCE_NODE = 'Merge2';

// Pull all items from Merge2
const srcItems = $items(SOURCE_NODE, 0, 0) || [];
if (!srcItems.length) return [{ json: {} }];

const urls = [];

// Collect all resultUrls (duplicates allowed)
for (const it of srcItems) {
  const resultUrls = it.json?.data?.response?.resultUrls || [];
  for (const url of resultUrls) {
    if (typeof url === 'string' && url.startsWith('http')) {
      urls.push(url);
    }
  }
}

// Label them as url1, url2, url3, url4
const labeled = {};
urls.forEach((url, i) => (labeled[`url${i + 1}`] = url));

// Pad up to 4 URLs (use null placeholders if fewer)
while (Object.keys(labeled).length < 4) {
  const nextIndex = Object.keys(labeled).length + 1;
  labeled[`url${nextIndex}`] = null;
}

// Return labeled URLs
return [{ json: labeled }];

